import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { 
  LucideAngularModule, 
  MessageSquare, 
  SquareSplitHorizontal, 
  Paperclip, 
  ArrowUp, 
  ShieldCheck, 
  ChevronDown,
  ArrowRightLeft, 
  TrendingDown, 
  TrendingUp, 
  Languages 
} from 'lucide-angular';

@Component({
  selector: 'app-chat',
  standalone: true,
  imports: [CommonModule, FormsModule, LucideAngularModule],
  templateUrl: './chat.component.html',
  styleUrls: ['./chat.component.scss']
})
export class ChatComponent {
  messageInput: string = '';
  
  // Mappage des icônes obligatoires pour correspondre au design épuré
  iconMessage = MessageSquare;
  iconSidebar = SquareSplitHorizontal;
  iconPaperclip = Paperclip;
  iconArrowUp = ArrowUp;
  iconShield = ShieldCheck;
  iconChevronDown = ChevronDown;

  // Configuration des 4 boîtes horizontales exactement comme dans la capture chat.jpg
  suggestions = [
    { 
      title: "Effectuer un virement ou déplacer des fonds", 
      desc: "Option de transfert", 
      textToInject: "Je souhaite faire un transfert de 450€ vers le compte de production",
      icon: ArrowRightLeft, 
      iconColor: 'text-purple-400' 
    },
    { 
      title: "Enregistrer une dépense ou facture payée", 
      desc: "Option de débit", 
      textToInject: "Débite mon compte du montant de la facture EDF reçue hier",
      icon: TrendingDown, 
      iconColor: 'text-rose-400' 
    },
    { 
      title: "Vérifier la bonne réception d'un paiement", 
      desc: "Option de crédit", 
      textToInject: "Est-ce qu'on a reçu le crédit pour la facture de DWEXO ?",
      icon: TrendingUp, 
      iconColor: 'text-emerald-400' 
    },
    { 
      title: "Échanger dans votre langue préférée", 
      desc: "Multilingue intelligent", 
      textToInject: "أريد مراجعة المعاملات الأخيرة لشركتي",
      icon: Languages, 
      iconColor: 'text-blue-400' 
    }
  ];

  triggerSubmit() {
    if (!this.messageInput.trim()) return;
    
    // Simulation d'envoi vers le backend Python (LangGraph + Orchestrateur MCP)
    console.log("Payload envoyé à l'agent :", this.messageInput);
    
    this.messageInput = ''; 
  }

  injectSuggestion(text: string) {
    this.messageInput = text;
  }
}
